1	// Core domain types and logic for the MHPCO claim office.
2	
3	export type ItemType = 'sword' | 'amulet' | 'staff' | 'potion' | 'rune' | 'moonstone';
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface Customer {
13	  yearsWithMHPCO: number;
14	}
15	
16	export interface Damage {
17	  itemType: string;
18	  amount: number;
19	}
20	
21	export interface Incident {
22	  cause: string;
23	  damages: Damage[];
24	}
25	
26	export type Step =
27	  | { op: 'quote'; items: Item[] }
28	  | { op: 'claim'; policy: number; incident: Incident };
29	
30	export interface Scenario {
31	  customer: Customer;
32	  steps: Step[];
33	}
34	
35	export type StepResult =
36	  | { premium: number }
37	  | { payout: number; remainingCap: number };
38	
39	export interface ScenarioResult {
40	  results: StepResult[];
41	}
42	
43	interface Policy {
44	  items: Item[];
45	  insuranceSum: number;
46	  remainingCap: number;
47	}
48	
49	interface PriceListEntry {
50	  insuranceValue: number;
51	  basePremium: number;
52	}
53	
54	const MAIN_ITEM_PRICES: Record<string, PriceListEntry> = {
55	  sword:  { insuranceValue: 1000, basePremium: 100 },
56	  amulet: { insuranceValue: 600,  basePremium: 60 },
57	  staff:  { insuranceValue: 800,  basePremium: 80 },
58	  potion: { insuranceValue: 400,  basePremium: 40 },
59	};
60	
61	const COMPONENT_TYPES = new Set(['rune', 'moonstone']);
62	const COMPONENT_INSURANCE_VALUE = 250;
63	const COMPONENT_BASE_PREMIUM = 25;
64	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
65	const COMPONENT_BLOCK_SIZE = 3;
66	
67	const PROCESSING_FEE = 5;
68	const DEDUCTIBLE = 100;
69	
70	function isKnownType(type: string): boolean {
71	  return type in MAIN_ITEM_PRICES || COMPONENT_TYPES.has(type);
72	}
73	
74	function isComponent(type: string): boolean {
75	  return COMPONENT_TYPES.has(type);
76	}
77	
78	function itemInsuranceValue(item: Item): number {
79	  if (item.type in MAIN_ITEM_PRICES) {
80	    return MAIN_ITEM_PRICES[item.type].insuranceValue;
81	  }
82	  if (isComponent(item.type)) {
83	    return COMPONENT_INSURANCE_VALUE;
84	  }
85	  throw new Error(`Unknown item type: ${item.type}`);
86	}
87	
88	function policyInsuranceSum(items: Item[]): number {
89	  return items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
90	}
91	
92	function itemBasePremium(item: Item): number {
93	  if (item.type in MAIN_ITEM_PRICES) {
94	    return MAIN_ITEM_PRICES[item.type].basePremium;
95	  }
96	  if (isComponent(item.type)) {
97	    return COMPONENT_BASE_PREMIUM;
98	  }
99	  throw new Error(`Unknown item type: ${item.type}`);
100	}
101	
102	// Compute total base premium for items, applying the block discount for
103	// components: each group of exactly 3 alike components is one block at 60 G;
104	// remaining components are billed at 25 G each.
105	function itemsBasePremium(items: Item[]): number {
106	  const componentCounts: Record<string, number> = {};
107	  let total = 0;
108	
109	  for (const item of items) {
110	    if (isComponent(item.type)) {
111	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
112	    } else {
113	      total += itemBasePremium(item);
114	    }
115	  }
116	
117	  for (const type in componentCounts) {
118	    const count = componentCounts[type];
119	    if (count === COMPONENT_BLOCK_SIZE) {
120	      total += COMPONENT_BLOCK_BASE_PREMIUM;
121	    } else {
122	      total += count * COMPONENT_BASE_PREMIUM;
123	    }
124	  }
125	
126	  return total;
127	}
128	
129	function itemSurcharge(item: Item): number {
130	  const base = itemBasePremium(item);
131	  let surcharge = 0;
132	  if (item.cursed) {
133	    surcharge += base * 0.5;
134	  }
135	  if ((item.enchantment ?? 0) >= 5) {
136	    surcharge += base * 0.3;
137	  }
138	  return surcharge;
139	}
140	
141	function itemsSurcharge(items: Item[]): number {
142	  return items.reduce((sum, item) => sum + itemSurcharge(item), 0);
143	}
144	
145	function roundUp(value: number): number {
146	  return Math.ceil(value);
147	}
148	
149	function roundDown(value: number): number {
150	  return Math.floor(value);
151	}
152	
153	export function computePremium(
154	  customer: Customer,
155	  items: Item[],
156	  isFollowUp: boolean,
157	): number {
158	  for (const item of items) {
159	    if (!isKnownType(item.type)) {
160	      throw new Error(`Unknown item type: ${item.type}`);
161	    }
162	  }
163	
164	  const policyBase = itemsBasePremium(items);
165	  const itemSurcharges = itemsSurcharge(items);
166	
167	  // Item base + item-specific surcharges form the per-item subtotal.
168	  // Policy-wide modifiers apply to policyBase (per the spec: loyalty,
169	  // first-insurance and follow-up are described as policy-wide; the
170	  // first-insurance modifier is treated per-item per the integration note).
171	  let total = policyBase + itemSurcharges;
172	
173	  // First insurance surcharge: 10% per item, applied to that item's base.
174	  for (const item of items) {
175	    total += itemBasePremium(item) * 0.1;
176	  }
177	
178	  if (customer.yearsWithMHPCO >= 2) {
179	    total -= policyBase * 0.2;
180	  }
181	  if (isFollowUp) {
182	    total -= policyBase * 0.15;
183	  }
184	
185	  total += PROCESSING_FEE;
186	  return roundUp(total);
187	}
188	
189	function makePolicy(items: Item[]): Policy {
190	  const insuranceSum = policyInsuranceSum(items);
191	  return {
192	    items: [...items],
193	    insuranceSum,
194	    remainingCap: insuranceSum * 2,
195	  };
196	}
197	
198	function damageReimbursement(item: Item, amount: number): number {
199	  const highEnchant = (item.enchantment ?? 0) >= 8;
200	  if (highEnchant) {
201	    return amount * 0.5;
202	  }
203	  return amount;
204	}
205	
206	export function computeClaim(
207	  policy: Policy,
208	  incident: Incident,
209	): { payout: number; remainingCap: number } {
210	  if (incident.damages.some((d) => d.amount < 0)) {
211	    throw new Error('Negative damage amount');
212	  }
213	
214	  // Validate: every damage must correspond to an actual covered item.
215	  // Map item types to a queue of items so multiple of same type are matched.
216	  const available: Record<string, Item[]> = {};
217	  for (const item of policy.items) {
218	    if (!available[item.type]) available[item.type] = [];
219	    available[item.type].push(item);
220	  }
221	  const matched: { item: Item; amount: number }[] = [];
222	  const consumed: Record<string, number> = {};
223	  for (const dmg of incident.damages) {
224	    if (!isKnownType(dmg.itemType)) {
225	      throw new Error(`Unknown item type in damage: ${dmg.itemType}`);
226	    }
227	    const pool = available[dmg.itemType] ?? [];
228	    const used = consumed[dmg.itemType] ?? 0;
229	    if (used >= pool.length) {
230	      throw new Error(`Damage references item not in policy: ${dmg.itemType}`);
231	    }
232	    matched.push({ item: pool[used], amount: dmg.amount });
233	    consumed[dmg.itemType] = used + 1;
234	  }
235	
236	  let totalPayout = 0;
237	  for (const { item, amount } of matched) {
238	    const reimbursed = damageReimbursement(item, amount);
239	    const afterDeductible = Math.max(0, reimbursed - DEDUCTIBLE);
240	    totalPayout += afterDeductible;
241	  }
242	
243	  let payout = roundDown(totalPayout);
244	  if (payout > policy.remainingCap) {
245	    payout = policy.remainingCap;
246	  }
247	  policy.remainingCap -= payout;
248	  return { payout, remainingCap: policy.remainingCap };
249	}
250	
251	export function runScenario(scenario: Scenario): ScenarioResult {
252	  const results: StepResult[] = [];
253	  const policies: (Policy | null)[] = [];
254	  let quoteCount = 0;
255	
256	  for (const step of scenario.steps) {
257	    if (step.op === 'quote') {
258	      const isFollowUp = quoteCount > 0;
259	      const premium = computePremium(scenario.customer, step.items, isFollowUp);
260	      const policy = makePolicy(step.items);
261	      policies.push(policy);
262	      results.push({ premium });
263	      quoteCount += 1;
264	    } else if (step.op === 'claim') {
265	      const policy = policies[step.policy];
266	      if (!policy) {
267	        throw new Error(`Claim references nonexistent policy: ${step.policy}`);
268	      }
269	      const result = computeClaim(policy, step.incident);
270	      policies.push(null);
271	      results.push(result);
272	    } else {
273	      throw new Error(`Unknown op`);
274	    }
275	  }
276	
277	  return { results };
278	}
