1	#!/usr/bin/env node
2	import { runScenario, Scenario } from './claim-office.js';
3	
4	async function readStdin(): Promise<string> {
5	  return new Promise((resolve, reject) => {
6	    let data = '';
7	    process.stdin.setEncoding('utf8');
8	    process.stdin.on('data', (chunk) => {
9	      data += chunk;
10	    });
11	    process.stdin.on('end', () => resolve(data));
12	    process.stdin.on('error', reject);
13	  });
14	}
15	
16	async function main(): Promise<void> {
17	  try {
18	    const input = await readStdin();
19	    const scenario = JSON.parse(input) as Scenario;
20	    const output = runScenario(scenario);
21	    process.stdout.write(JSON.stringify(output));
22	  } catch (err) {
23	    const message = err instanceof Error ? err.message : String(err);
24	    process.stderr.write(`Error: ${message}\n`);
25	    process.exit(1);
26	  }
27	}
28	
29	main();
