4	function runQuote(items: any[], yearsWithMHPCO = 0, priorQuotes = 0): number {
5	  const steps: any[] = [];
6	  for (let i = 0; i < priorQuotes; i++) {
7	    steps.push({ op: 'quote', items: [] });
8	  }
9	  steps.push({ op: 'quote', items });
10	  const scenario: Scenario = { customer: { yearsWithMHPCO }, steps };
11	  const result = runScenario(scenario);
12	  return (result.results[priorQuotes] as { premium: number }).premium;
13	}
