67	const PROCESSING_FEE = 5;
68	const DEDUCTIBLE = 100;
69	
70	function priceFor(type: string): PriceListEntry {
71	  const entry = PRICE_LIST[type];
72	  if (!entry) {
73	    throw new Error(`Unknown item type: ${type}`);
74	  }
75	  return entry;
76	}
77	
78	function isComponent(type: string): boolean {
79	  return priceFor(type).isComponent;
80	}
81	
82	function itemInsuranceValue(item: Item): number {
83	  return priceFor(item.type).insuranceValue;
84	}
85	
86	function policyInsuranceSum(items: Item[]): number {
87	  return items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
88	}
89	
90	function itemBasePremium(item: Item): number {
91	  return priceFor(item.type).basePremium;
92	}
93	
94	// Compute total base premium for items, applying the block discount for
95	// components: each group of exactly 3 alike components is one block at 60 G;
96	// remaining components are billed at 25 G each.
97	function itemsBasePremium(items: Item[]): number {
98	  const componentCounts: Record<string, number> = {};
99	  let total = 0;
100	
101	  for (const item of items) {
102	    if (isComponent(item.type)) {
103	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
104	    } else {
105	      total += itemBasePremium(item);
106	    }
107	  }
108	
109	  for (const type in componentCounts) {
110	    const count = componentCounts[type];
111	    if (count === COMPONENT_BLOCK_SIZE) {
112	      total += COMPONENT_BLOCK_BASE_PREMIUM;
113	    } else {
114	      total += count * priceFor(type).basePremium;
115	    }
116	  }
117	
118	  return total;
119	}
120	
121	function itemSurcharge(item: Item): number {
122	  const base = itemBasePremium(item);
123	  let surcharge = 0;
124	  if (item.cursed) {
125	    surcharge += base * 0.5;
126	  }
127	  if ((item.enchantment ?? 0) >= 5) {
128	    surcharge += base * 0.3;
129	  }
130	  return surcharge;
131	}
132	
133	function itemsSurcharge(items: Item[]): number {
134	  return items.reduce((sum, item) => sum + itemSurcharge(item), 0);
135	}
136	
137	// First-insurance is applied per item against the item's own base premium
138	// (the un-blocked price), per the integration note in the spec: each item
139	// in a quote is treated as a first insurance regardless of customer history.
140	function firstInsuranceSurcharge(items: Item[]): number {
141	  return items.reduce((sum, item) => sum + itemBasePremium(item) * 0.1, 0);
142	}
143	
144	export function computePremium(
145	  customer: Customer,
146	  items: Item[],
147	  isFollowUp: boolean,
148	): number {
149	  // priceFor (called transitively below) throws on unknown types.
150	  const policyBase = itemsBasePremium(items);
151	  const itemSurcharges = itemsSurcharge(items);
152	
153	  // Item base + item-specific surcharges form the per-item subtotal.
154	  // Loyalty and follow-up discounts are policy-wide on policyBase.
155	  let total = policyBase + itemSurcharges + firstInsuranceSurcharge(items);
156	
157	  if (customer.yearsWithMHPCO >= 2) {
158	    total -= policyBase * 0.2;
159	  }
160	  if (isFollowUp) {
161	    total -= policyBase * 0.15;
162	  }
163	
164	  total += PROCESSING_FEE;
165	  return Math.ceil(total);
166	}
167	
168	function makePolicy(items: Item[]): Policy {
169	  const insuranceSum = policyInsuranceSum(items);
170	  return {
171	    items: [...items],
172	    insuranceSum,
173	    remainingCap: insuranceSum * 2,
174	  };
175	}
176	
177	function damageReimbursement(item: Item, amount: number): number {
178	  const highEnchant = (item.enchantment ?? 0) >= 8;
179	  if (highEnchant) {
180	    return amount * 0.5;
181	  }
182	  return amount;
183	}
184	
185	// Match each damage entry to a covered item, consuming items in order so
186	// that N damages of the same type require at least N items of that type.
187	function matchDamagesToItems(
188	  policyItems: Item[],
189	  damages: Damage[],
190	): { item: Item; amount: number }[] {
191	  const available: Record<string, Item[]> = {};
192	  for (const item of policyItems) {
193	    (available[item.type] ??= []).push(item);
194	  }
195	
196	  const consumed: Record<string, number> = {};
197	  return damages.map((dmg) => {
198	    priceFor(dmg.itemType); // validate type
199	    const pool = available[dmg.itemType] ?? [];
200	    const used = consumed[dmg.itemType] ?? 0;
201	    if (used >= pool.length) {
202	      throw new Error(`Damage references item not in policy: ${dmg.itemType}`);
203	    }
204	    consumed[dmg.itemType] = used + 1;
205	    return { item: pool[used], amount: dmg.amount };
206	  });
207	}
208	
209	export function computeClaim(
210	  policy: Policy,
211	  incident: Incident,
212	): { payout: number; remainingCap: number } {
213	  if (incident.damages.some((d) => d.amount < 0)) {
214	    throw new Error('Negative damage amount');
215	  }
216	
217	  const matched = matchDamagesToItems(policy.items, incident.damages);
218	
219	  const totalPayout = matched.reduce((sum, { item, amount }) => {
220	    const reimbursed = damageReimbursement(item, amount);
221	    return sum + Math.max(0, reimbursed - DEDUCTIBLE);
222	  }, 0);
223	
224	  const payout = Math.min(Math.floor(totalPayout), policy.remainingCap);
225	  policy.remainingCap -= payout;
226	  return { payout, remainingCap: policy.remainingCap };
227	}
228	
229	export function runScenario(scenario: Scenario): ScenarioResult {
230	  // Policies are keyed by the step index of the quote that created them,
231	  // so later claim steps can look them up via their `policy` field.
232	  const policiesByStepIndex = new Map<number, Policy>();
233	  let quoteCount = 0;
234	
235	  return {
236	    results: scenario.steps.map((step, stepIndex) => {
237	      if (step.op === 'quote') {
238	        const isFollowUp = quoteCount > 0;
239	        quoteCount += 1;
240	        policiesByStepIndex.set(stepIndex, makePolicy(step.items));
241	        return { premium: computePremium(scenario.customer, step.items, isFollowUp) };
242	      }
243	      if (step.op === 'claim') {
244	        const policy = policiesByStepIndex.get(step.policy);
245	        if (!policy) {
246	          throw new Error(`Claim references nonexistent policy: ${step.policy}`);
247	        }
248	        return computeClaim(policy, step.incident);
249	      }
250	      throw new Error(`Unknown op`);
251	    }),
252	  };
253	}
